+pub struct SbomDependency {
+    /// Dependency name.
+    pub name: String,
+
+    /// Dependency version.
+    pub version: String,
+
+    /// PURL (Package URL).
+    pub purl: String,
+
+    /// Source (crates.io, git, path).
+    pub source: String,
+}
